def main() -> None:
    if len(sys.argv) < 2:
        print_usage()
        sys.exit(1)

    command = sys.argv[1].lower()

    if command == "publish":
        if len(sys.argv) < 3:
            print_usage()
            sys.exit(1)
        try:
            task = json.loads(sys.argv[2])
        except json.JSONDecodeError as exc:
            print(f"Invalid JSON: {exc}")
            sys.exit(1)
        publish_task(task)
    elif command == "consume":
        consume_tasks()
